import React, { useEffect, useRef } from 'react';

const Parallax = ({ images, scrollPercentage }) => {
    const imageRefs = useRef([]);

    useEffect(() => {
        const handleScroll = () => {
            images.forEach((image, index) => {
                const element = imageRefs.current[index];
                if (element) {
                    const displacement = (scrollPercentage / 100) * (window.innerWidth - element.offsetWidth); // Calculamos el desplazamiento en función del porcentaje y el ancho de la ventana y la imagen
                    element.style.marginLeft = (displacement * image.imgSpeed) + image.imgOffset + 'px'; // Aplicamos el parallax en X
                }
            });
        };

        document.addEventListener('scroll', handleScroll);

        return () => {
            document.removeEventListener('scroll', handleScroll);
        };
    }, [images, scrollPercentage]);

    return (
        <div>
            {images.map((image, index) => (
                <img
                    key={index}
                    ref={el => imageRefs.current[index] = el}
                    src={image.imgSrc}
                    alt=""
                    style={{ display: 'block' }} // Agregamos display: block para evitar espacios adicionales
                />
            ))}
        </div>
    );
};

export default Parallax;
